"""Fetch PostHog GitHub data for last 90 days via gh CLI (GraphQL + REST)."""
from __future__ import annotations
import json
import subprocess
import sys
from datetime import datetime, timedelta, timezone
from pathlib import Path

REPO_OWNER = "PostHog"
REPO_NAME = "posthog"
WINDOW_DAYS = 90
DATA_DIR = Path(__file__).parent.parent / "data" / "raw"
DATA_DIR.mkdir(parents=True, exist_ok=True)

NOW = datetime.now(timezone.utc)
SINCE = NOW - timedelta(days=WINDOW_DAYS)
SINCE_ISO = SINCE.strftime("%Y-%m-%dT%H:%M:%SZ")


def gh_api(args: list[str]) -> dict | list:
    """Run gh api with given args and return parsed JSON."""
    result = subprocess.run(
        ["gh", "api"] + args,
        capture_output=True,
        text=True,
        timeout=120,
    )
    if result.returncode != 0:
        raise RuntimeError(f"gh api failed: {result.stderr[:500]}")
    return json.loads(result.stdout) if result.stdout.strip() else {}


def gh_graphql(query: str, variables: dict) -> dict:
    """Run a GraphQL query via gh api graphql."""
    args = ["graphql", "-f", f"query={query}"]
    for k, v in variables.items():
        if isinstance(v, str):
            args += ["-F", f"{k}={v}"]
        else:
            args += ["-F", f"{k}={v}"]
    result = subprocess.run(
        ["gh"] + ["api"] + args,
        capture_output=True,
        text=True,
        timeout=120,
    )
    if result.returncode != 0:
        raise RuntimeError(f"graphql failed: {result.stderr[:500]}")
    return json.loads(result.stdout)


PR_QUERY = """
query($owner:String!, $name:String!, $cursor:String) {
  repository(owner:$owner, name:$name) {
    pullRequests(first:50, after:$cursor, states:[MERGED,CLOSED], orderBy:{field:UPDATED_AT, direction:DESC}) {
      pageInfo { hasNextPage endCursor }
      nodes {
        number
        title
        url
        state
        merged
        mergedAt
        createdAt
        updatedAt
        additions
        deletions
        changedFiles
        author { login ... on User { databaseId } }
        labels(first:20) { nodes { name } }
        reviews(first:50) {
          nodes {
            author { login }
            state
            submittedAt
            comments { totalCount }
          }
        }
        comments(first:30) {
          nodes { author { login } createdAt }
        }
        reviewRequests(first:20) {
          nodes { requestedReviewer { ... on User { login } } }
        }
        files(first:100) {
          nodes { path additions deletions }
        }
        closingIssuesReferences(first:10) {
          nodes { number title labels(first:10){ nodes { name } } }
        }
        timelineItems(first:30, itemTypes:[HEAD_REF_FORCE_PUSHED_EVENT, REVERTED_EVENT, CROSS_REFERENCED_EVENT]) {
          nodes {
            __typename
            ... on CrossReferencedEvent {
              source { ... on PullRequest { number mergedAt } ... on Issue { number } }
            }
          }
        }
      }
    }
  }
}
"""


def fetch_prs() -> list[dict]:
    """Fetch all PRs updated within the window."""
    prs = []
    cursor = None
    page = 0
    while True:
        page += 1
        variables = {"owner": REPO_OWNER, "name": REPO_NAME}
        if cursor:
            variables["cursor"] = cursor
        # Build args manually because gh api graphql -F doesn't pass null cleanly
        args = ["graphql", "-f", f"query={PR_QUERY}", "-f", f"owner={REPO_OWNER}", "-f", f"name={REPO_NAME}"]
        if cursor:
            args += ["-f", f"cursor={cursor}"]
        result = subprocess.run(["gh", "api"] + args, capture_output=True, text=True, timeout=120)
        if result.returncode != 0:
            raise RuntimeError(f"PR fetch failed page {page}: {result.stderr[:500]}")
        data = json.loads(result.stdout)
        pr_data = data["data"]["repository"]["pullRequests"]
        nodes = pr_data["nodes"]
        # Stop once we go past the window
        stop = False
        for pr in nodes:
            updated = datetime.fromisoformat(pr["updatedAt"].replace("Z", "+00:00"))
            if updated < SINCE:
                stop = True
                break
            prs.append(pr)
        print(f"  page {page}: {len(nodes)} PRs, total kept {len(prs)}", file=sys.stderr)
        if stop or not pr_data["pageInfo"]["hasNextPage"]:
            break
        cursor = pr_data["pageInfo"]["endCursor"]
    return prs


ISSUE_QUERY = """
query($owner:String!, $name:String!, $cursor:String) {
  repository(owner:$owner, name:$name) {
    issues(first:50, after:$cursor, orderBy:{field:UPDATED_AT, direction:DESC}) {
      pageInfo { hasNextPage endCursor }
      nodes {
        number
        title
        url
        state
        createdAt
        updatedAt
        closedAt
        author { login ... on User { databaseId } }
        authorAssociation
        labels(first:20) { nodes { name } }
        comments(first:30) {
          nodes { author { login } authorAssociation createdAt }
        }
      }
    }
  }
}
"""


def fetch_issues() -> list[dict]:
    issues = []
    cursor = None
    page = 0
    while True:
        page += 1
        args = ["graphql", "-f", f"query={ISSUE_QUERY}", "-f", f"owner={REPO_OWNER}", "-f", f"name={REPO_NAME}"]
        if cursor:
            args += ["-f", f"cursor={cursor}"]
        result = subprocess.run(["gh", "api"] + args, capture_output=True, text=True, timeout=120)
        if result.returncode != 0:
            raise RuntimeError(f"issue fetch failed page {page}: {result.stderr[:500]}")
        data = json.loads(result.stdout)
        issue_data = data["data"]["repository"]["issues"]
        nodes = issue_data["nodes"]
        stop = False
        for iss in nodes:
            updated = datetime.fromisoformat(iss["updatedAt"].replace("Z", "+00:00"))
            if updated < SINCE:
                stop = True
                break
            issues.append(iss)
        print(f"  issues page {page}: {len(nodes)}, total kept {len(issues)}", file=sys.stderr)
        if stop or not issue_data["pageInfo"]["hasNextPage"]:
            break
        cursor = issue_data["pageInfo"]["endCursor"]
    return issues


def fetch_codeowners() -> str:
    for path in [".github/CODEOWNERS", "CODEOWNERS", "docs/CODEOWNERS"]:
        try:
            data = gh_api([f"repos/{REPO_OWNER}/{REPO_NAME}/contents/{path}"])
            import base64
            return base64.b64decode(data["content"]).decode("utf-8", errors="replace")
        except Exception:
            continue
    return ""


def fetch_org_members() -> list[str]:
    """Best-effort fetch of PostHog public org members. May be limited."""
    try:
        members = gh_api([f"orgs/{REPO_OWNER}/public_members", "--paginate"])
        if isinstance(members, list):
            return [m["login"] for m in members]
    except Exception as e:
        print(f"  org members fetch failed: {e}", file=sys.stderr)
    return []


def main():
    print(f"Window: {SINCE_ISO} to {NOW.isoformat()}", file=sys.stderr)
    print("Fetching PRs...", file=sys.stderr)
    prs = fetch_prs()
    (DATA_DIR / "prs.json").write_text(json.dumps(prs))
    print(f"Saved {len(prs)} PRs", file=sys.stderr)

    print("Fetching issues...", file=sys.stderr)
    issues = fetch_issues()
    (DATA_DIR / "issues.json").write_text(json.dumps(issues))
    print(f"Saved {len(issues)} issues", file=sys.stderr)

    print("Fetching CODEOWNERS...", file=sys.stderr)
    co = fetch_codeowners()
    (DATA_DIR / "codeowners.txt").write_text(co)
    print(f"CODEOWNERS: {len(co)} chars", file=sys.stderr)

    print("Fetching org public members...", file=sys.stderr)
    members = fetch_org_members()
    (DATA_DIR / "org_members.json").write_text(json.dumps(members))
    print(f"Org public members: {len(members)}", file=sys.stderr)

    meta = {"since": SINCE_ISO, "now": NOW.isoformat(), "window_days": WINDOW_DAYS}
    (DATA_DIR / "meta.json").write_text(json.dumps(meta))


if __name__ == "__main__":
    main()

