"""Fetch PostHog GitHub data for last 90 days via gh CLI (GraphQL + REST).

Incremental save per page; unbuffered prints for progress.
"""
from __future__ import annotations
import json
import subprocess
import sys
from datetime import datetime, timedelta, timezone
from pathlib import Path

REPO_OWNER = "PostHog"
REPO_NAME = "posthog"
WINDOW_DAYS = 90
PAGE_SIZE = 30

DATA_DIR = Path(__file__).parent.parent / "data" / "raw"
DATA_DIR.mkdir(parents=True, exist_ok=True)

NOW = datetime.now(timezone.utc)
SINCE = NOW - timedelta(days=WINDOW_DAYS)
SINCE_ISO = SINCE.strftime("%Y-%m-%dT%H:%M:%SZ")


def log(msg: str):
    print(msg, file=sys.stderr, flush=True)


def gh_api(args: list[str]) -> dict | list:
    result = subprocess.run(["gh", "api"] + args, capture_output=True, text=True, timeout=120)
    if result.returncode != 0:
        raise RuntimeError(f"gh api failed: {result.stderr[:500]}")
    return json.loads(result.stdout) if result.stdout.strip() else {}


PR_QUERY = """
query($owner:String!, $name:String!, $cursor:String, $first:Int!) {
  repository(owner:$owner, name:$name) {
    pullRequests(first:$first, after:$cursor, states:[MERGED,CLOSED], orderBy:{field:UPDATED_AT, direction:DESC}) {
      pageInfo { hasNextPage endCursor }
      nodes {
        number title url state merged mergedAt createdAt updatedAt
        additions deletions changedFiles
        author { login ... on User { databaseId } }
        labels(first:15) { nodes { name } }
        reviews(first:30) {
          nodes {
            author { login }
            state
            submittedAt
            comments { totalCount }
          }
        }
        reviewRequests(first:15) {
          nodes { requestedReviewer { ... on User { login } } }
        }
        files(first:80) {
          nodes { path additions deletions }
        }
        closingIssuesReferences(first:5) {
          nodes { number title labels(first:8){ nodes { name } } }
        }
      }
    }
  }
}
"""


def fetch_paginated(query: str, key_path: list[str], out_file: Path, label: str) -> list[dict]:
    """Generic paginated GraphQL fetcher with incremental save and window cutoff."""
    items = []
    cursor = None
    page = 0
    while True:
        page += 1
        args = ["graphql", "-f", f"query={query}",
                "-f", f"owner={REPO_OWNER}", "-f", f"name={REPO_NAME}",
                "-F", f"first={PAGE_SIZE}"]
        if cursor:
            args += ["-f", f"cursor={cursor}"]
        result = subprocess.run(["gh", "api"] + args, capture_output=True, text=True, timeout=120)
        if result.returncode != 0:
            log(f"  {label} page {page} FAILED: {result.stderr[:300]}")
            # Retry once
            result = subprocess.run(["gh", "api"] + args, capture_output=True, text=True, timeout=120)
            if result.returncode != 0:
                raise RuntimeError(f"{label} page {page} failed twice: {result.stderr[:300]}")
        data = json.loads(result.stdout)
        node = data["data"]["repository"]
        for k in key_path:
            node = node[k]
        page_info = node["pageInfo"]
        nodes = node["nodes"]
        stop = False
        for n in nodes:
            updated = datetime.fromisoformat(n["updatedAt"].replace("Z", "+00:00"))
            if updated < SINCE:
                stop = True
                break
            items.append(n)
        log(f"  {label} page {page}: +{len(nodes)} items, total {len(items)}")
        # incremental save
        out_file.write_text(json.dumps(items))
        if stop or not page_info["hasNextPage"]:
            break
        cursor = page_info["endCursor"]
    return items


ISSUE_QUERY = """
query($owner:String!, $name:String!, $cursor:String, $first:Int!) {
  repository(owner:$owner, name:$name) {
    issues(first:$first, after:$cursor, orderBy:{field:UPDATED_AT, direction:DESC}) {
      pageInfo { hasNextPage endCursor }
      nodes {
        number title url state createdAt updatedAt closedAt
        author { login }
        authorAssociation
        labels(first:15) { nodes { name } }
        comments(first:20) {
          nodes { author { login } authorAssociation createdAt }
        }
      }
    }
  }
}
"""


def fetch_codeowners() -> str:
    import base64
    for path in [".github/CODEOWNERS", "CODEOWNERS", "docs/CODEOWNERS"]:
        try:
            data = gh_api([f"repos/{REPO_OWNER}/{REPO_NAME}/contents/{path}"])
            return base64.b64decode(data["content"]).decode("utf-8", errors="replace")
        except Exception:
            continue
    return ""


def fetch_org_members() -> list[str]:
    try:
        members = gh_api([f"orgs/{REPO_OWNER}/public_members", "--paginate"])
        if isinstance(members, list):
            return [m["login"] for m in members]
    except Exception as e:
        log(f"  org members fetch failed: {e}")
    return []


def main():
    log(f"Window: {SINCE_ISO} to {NOW.isoformat()}")
    log("Fetching PRs...")
    prs = fetch_paginated(PR_QUERY, ["pullRequests"], DATA_DIR / "prs.json", "PRs")
    log(f"Saved {len(prs)} PRs")

    log("Fetching issues...")
    issues = fetch_paginated(ISSUE_QUERY, ["issues"], DATA_DIR / "issues.json", "issues")
    log(f"Saved {len(issues)} issues")

    log("Fetching CODEOWNERS...")
    co = fetch_codeowners()
    (DATA_DIR / "codeowners.txt").write_text(co)
    log(f"CODEOWNERS: {len(co)} chars")

    log("Fetching org public members...")
    members = fetch_org_members()
    (DATA_DIR / "org_members.json").write_text(json.dumps(members))
    log(f"Org public members: {len(members)}")

    meta = {"since": SINCE_ISO, "now": NOW.isoformat(), "window_days": WINDOW_DAYS}
    (DATA_DIR / "meta.json").write_text(json.dumps(meta))
    log("DONE")


if __name__ == "__main__":
    main()

