        s = data["data"]["search"]
        nodes = [n for n in s["nodes"] if n]  # filter empties from non-PR types
        items.extend(nodes)
        log(f"  chunk {start.date()}..{end.date()} page {page}: +{len(nodes)} (cumulative {len(items)}/{s['issueCount']})")
        if not s["pageInfo"]["hasNextPage"]:
